+/// E2E test runner commands (br-8zmc).
+#[derive(Subcommand, Debug)]
+pub enum E2eCommand {
+    /// List available E2E test suites.
+    #[command(name = "list")]
+    List {
+        /// Output as JSON.
+        #[arg(long)]
+        json: bool,
+        /// Show suite details (descriptions, tags).
+        #[arg(long, short = 'v')]
+        verbose: bool,
